const EXPECT = '';
const root = $input.first().json;
const headers = root.headers || {};
const b = root.body !== undefined && root.body !== null ? root.body : root;
const hdrSecret = headers['x-recall-secret'] || headers['X-Recall-Secret'] || '';
const token = String(hdrSecret || b.secret || '').trim();
if (EXPECT && token !== EXPECT) {
  return [{ json: { _error: 'Unauthorized: set X-Recall-Secret header or body.secret, or leave EXPECT empty in this node' } }];
}
const chatId = String(b.chat_id ?? b.telegram_chat_id ?? '').trim();
const sourceDefault = String(b.source ?? 'webhook_recall');
if (!chatId) {
  return [{ json: { _error: 'chat_id is required (Telegram chat id)' } }];
}
const idRaw = b.transcript_id ?? b.meeting_transcript_id ?? b.db_id;
const transcriptId = idRaw !== undefined && idRaw !== null && String(idRaw).trim() !== '' ? String(idRaw).trim() : '';
const transcript = String(b.transcript ?? '');
const hasTranscript = transcript.trim().length > 0;
const title = String(b.title ?? '');
if (transcriptId && hasTranscript) {
  return [{ json: { _error: 'Use either transcript_id (load from Supabase) or transcript (inline), not both' } }];
}
if (!transcriptId && !hasTranscript) {
  return [{ json: { _error: 'Provide transcript_id (bigint in meeting_transcripts) or transcript (text)' } }];
}
if (transcriptId) {
  return [{ json: { _route: 'db', transcript_id: transcriptId, chat_id: chatId, source: sourceDefault } }];
}
return [{ json: { _route: 'inline', title, transcript, chat_id: chatId, source: sourceDefault } }];

const row = $input.first().json;
const title = String(row.title ?? '').trim();
const transcript = String(row.transcript ?? '').trim();
if (!title && !transcript) {
  throw new Error('No meeting_transcripts row for this transcript_id, or empty title and transcript');
}
return [{ json: { title, transcript, chat_id: String(row.chat_id ?? ''), source: String(row.source ?? 'webhook_db_row') } }];
